import { forwardRef, type HTMLAttributes, type ReactNode } from "react";
import { Slot } from "@radix-ui/react-slot";
import { clsx } from "clsx";
import { type BoxLayoutProps, boxStyles } from "./Box.sprinkles";

interface BoxCustomProps extends BoxLayoutProps {
  /**
   * When true, renders the child element instead of a div,
   * merging Box's props and behavior onto the child.
   */
  asChild?: boolean;
  children?: ReactNode;
}

export interface BoxProps
  extends
    Omit<HTMLAttributes<HTMLDivElement>, keyof BoxCustomProps>,
    BoxCustomProps {}

export const Box = forwardRef<HTMLDivElement, BoxProps>(
  (
    {
      p,
      pt,
      pr,
      pb,
      pl,
      px,
      py,
      m,
      mt,
      mr,
      mb,
      ml,
      mx,
      my,
      asChild,
      className,
      children,
      ...props
    },
    ref
  ) => {
    const Component = asChild ? Slot : "div";
    const stylesClassName = boxStyles({
      p,
      pt,
      pr,
      pb,
      pl,
      px,
      py,
      m,
      mt,
      mr,
      mb,
      ml,
      mx,
      my,
    });

    return (
      <Component
        ref={ref}
        className={clsx(stylesClassName, className)}
        {...props}
      >
        {children}
      </Component>
    );
  }
);

Box.displayName = "Box";
